def set_budget(budgets, category, amount):
    """Set (or replace) the budget for a category and return the amount."""
    amount = float(amount)
    budgets[category] = amount
    return amount


def over_budget(report, budgets):
    """Return the rows of ``report`` whose total exceeds its budget.

    ``report`` is the output of :func:`category_report`. Categories with no
    budget set are not flagged. Each returned row is
    ``(category, count, total, budget)``.
    """
    flagged = []
    for category, count, total in report:
        budget = budgets.get(category)
        if budget is not None and total > budget:
            flagged.append((category, count, total, budget))
    return flagged

